package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.Binding;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Result binding sets must stay resolvable after the query iteration is closed — callers routinely drain results with
 * {@link QueryResults#asList} and read the values afterwards. The native BGP path returns lazy slot views whose values
 * materialize through the value store on access; that materialization must not be tied to the query's dataset lifetime
 * (found by differential fuzzing: a repeated-variable pattern query threw "Query evaluation was interrupted" from the
 * dataset-open assertion when the drained rows were read).
 */
public class LmdbNativeLazyResultAfterCloseTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI x = vf.createIRI(EX, "x");
			IRI z = vf.createIRI(EX, "z");
			IRI p1 = vf.createIRI(EX, "p1");
			conn.add(z, p1, z);
			conn.add(x, p1, z);
		}
	}

	@AfterEach
	public void tearDown() {
		if (repository != null) {
			repository.shutDown();
		}
	}

	@Test
	public void nativeRowsRemainReadableAfterRepositoryShutdown() {
		List<BindingSet> rows;
		try (SailRepositoryConnection conn = repository.getConnection()) {
			rows = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT * WHERE { ?a <" + EX + "p1> ?b . ?b <" + EX + "p1> ?b . }").evaluate());
		}
		assertThat(rows).hasSize(2);

		repository.shutDown();
		repository = null;

		for (BindingSet row : rows) {
			for (String bindingName : row.getBindingNames()) {
				assertThat(row.getValue(bindingName).stringValue()).startsWith(EX);
			}
		}
	}

	@Test
	public void repeatedVariablePatternRowsReadableAfterIterationCloses() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			// the repeated ?c variable routes this through the native BGP plan, whose rows are lazy views
			List<BindingSet> rows = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT * WHERE { ?c ?p ?c . ?a ?p ?c . }").evaluate());
			assertThat(rows).hasSize(2);
			for (BindingSet bs : rows) {
				for (Binding binding : bs) {
					assertThat(binding.getValue()).isNotNull();
				}
			}
		}
	}

	@Test
	public void plainJoinRowsReadableAfterIterationCloses() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT * WHERE { ?a <" + EX + "p1> ?b . ?b <" + EX + "p1> ?b . }").evaluate());
			assertThat(rows).hasSize(2);
			for (BindingSet bs : rows) {
				for (Binding binding : bs) {
					assertThat(binding.getValue()).isNotNull();
				}
			}
		}
	}
}
